import csv

questions = [
  {"id":"3781","tipo":"multipla","disciplina":"Matemática","tema":"Geometria","subtema":"Teorema de Tales","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Pelo Teorema de Tales, se duas retas transversais cortam um feixe de paralelas, os segmentos correspondentes são proporcionais. Se AB = 4, BC = 6 e DE = 3, qual é EF (correspondente a BC)?","alternativa_a":"4,5","alternativa_b":"3","alternativa_c":"2","alternativa_d":"6","alternativa_e":"5","resposta_correta":"a","explicacao":"Tales: AB/BC = DE/EF → 4/6 = 3/EF → EF = 3×6/4 = 18/4 = 4,5.","resposta":""},
  {"id":"3782","tipo":"multipla","disciplina":"Física","tema":"Acústica","subtema":"Intensidade Sonora","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A unidade de medida do nível de intensidade sonora é o:","alternativa_a":"Decibel (dB)","alternativa_b":"Hertz (Hz)","alternativa_c":"Pascal (Pa)","alternativa_d":"Watt (W)","alternativa_e":"Newton (N)","resposta_correta":"a","explicacao":"O decibel (dB) mede o nível de intensidade sonora em escala logarítmica. 0 dB = limiar da audição humana; 120 dB = limiar da dor. A frequência é medida em Hz; intensidade em W/m²; pressão em Pa.","resposta":""},
  {"id":"3783","tipo":"multipla","disciplina":"Química","tema":"Bioquímica","subtema":"Enzimas","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"As enzimas são catalisadores biológicos. Sua eficiência é altamente dependente de:","alternativa_a":"pH e temperatura (condições ótimas específicas para cada enzima)","alternativa_b":"Pressão atmosférica","alternativa_c":"Concentração de oxigênio","alternativa_d":"Densidade da solução","alternativa_e":"Campo magnético","resposta_correta":"a","explicacao":"Cada enzima tem pH e temperatura ótimos para sua atividade. Ex.: pepsina (estômago) atua em pH ≈ 2; amilase salivar em pH ≈ 7. Temperatura muito alta ou pH extremo desnatura a enzima (altera a conformação 3D), inativando-a.","resposta":""},
  {"id":"3784","tipo":"multipla","disciplina":"Biologia","tema":"Biologia Molecular","subtema":"PCR","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"A técnica de PCR (Reação em Cadeia da Polimerase) é usada para:","alternativa_a":"Amplificar (multiplicar) sequências específicas de DNA in vitro","alternativa_b":"Sequenciar proteínas","alternativa_c":"Produzir anticorpos monoclonais","alternativa_d":"Cultivar bactérias em laboratório","alternativa_e":"Sintetizar RNA a partir de proteínas","resposta_correta":"a","explicacao":"PCR (Mullis, 1983 — Nobel 1993): técnica que amplifica exponencialmente sequências específicas de DNA usando a enzima Taq polimerase. Ciclos de desnaturação (separação das fitas), anelamento de primers e extensão produzem bilhões de cópias. Aplicações: diagnóstico (COVID-19, HIV), medicina forense, pesquisa genética, testes de paternidade.","resposta":""},
  {"id":"3785","tipo":"multipla","disciplina":"História","tema":"Contemporânea","subtema":"Globalização","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A globalização econômica acelerou-se a partir dos anos 1980-90 impulsionada por:","alternativa_a":"Avanços em TI, queda do socialismo soviético, liberalização financeira e tratados de livre comércio","alternativa_b":"Apenas o crescimento da China","alternativa_c":"A Segunda Guerra Mundial","alternativa_d":"O surgimento dos BRICS","alternativa_e":"A Revolução Industrial do séc. XVIII","resposta_correta":"a","explicacao":"A globalização atual foi acelerada pela: Revolução da TI (internet, telecomunicações), queda do Muro de Berlim (1989) e fim da URSS (1991), neoliberalismo (Reagan/Thatcher), formação de blocos como NAFTA, UE, MERCOSUL, e Organização Mundial do Comércio (OMC, 1995).","resposta":""},
  {"id":"3786","tipo":"multipla","disciplina":"Geografia","tema":"Climatologia","subtema":"Tipos Climáticos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O clima semiárido do Nordeste brasileiro caracteriza-se por:","alternativa_a":"Chuvas irregulares e concentradas em poucos meses, com longos períodos de seca","alternativa_b":"Chuvas bem distribuídas o ano todo","alternativa_c":"Frio intenso no inverno","alternativa_d":"Alta umidade e temperaturas amenas","alternativa_e":"Precipitação anual superior a 2.000 mm","resposta_correta":"a","explicacao":"O semiárido nordestino tem precipitação média anual abaixo de 800 mm, irregularmente distribuída (regime de chuvas: fevereiro-maio). Longos períodos de seca (estiagem), alta evapotranspiração e caatinga como vegetação típica.","resposta":""},
  {"id":"3787","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Literatura","subtema":"Poesia Moderna","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Carlos Drummond de Andrade é o maior poeta modernista brasileiro. Qual é o poema que inicia com 'No meio do caminho tinha uma pedra'?","alternativa_a":"'No Meio do Caminho' (1928) — publicado na Revista de Antropofagia","alternativa_b":"'Morte e Vida Severina'","alternativa_c":"'Vou-me Embora pra Pasárgada'","alternativa_d":"'Evocação do Recife'","alternativa_e":"'Pneumotórax'","resposta_correta":"a","explicacao":"'No Meio do Caminho' é um dos poemas mais polêmicos do Modernismo brasileiro. A repetição anafórica ('No meio do caminho tinha uma pedra / tinha uma pedra no meio do caminho') simboliza os obstáculos da vida e da criação. Publicado por Drummond em 1928, foi visto como ruptura com a poesia tradicional.","resposta":""},
  {"id":"3788","tipo":"multipla","disciplina":"Filosofia","tema":"Hermenêutica","subtema":"Gadamer","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Hans-Georg Gadamer, em 'Verdade e Método', propõe que a compreensão é sempre mediada por:","alternativa_a":"A tradição e os preconceitos (pré-compreensões) do intérprete","alternativa_b":"Algoritmos objetivos de análise textual","alternativa_c":"A intenção original do autor","alternativa_d":"A estrutura lógico-formal do texto","alternativa_e":"A classe social do leitor","resposta_correta":"a","explicacao":"Para Gadamer, compreender um texto (ou obra cultural) nunca é neutro: o intérprete já carrega uma 'pré-compreensão' formada pela tradição em que vive ('horizonte'). A interpretação é uma 'fusão de horizontes' entre o texto e o intérprete — não há acesso direto ao sentido 'original'. Os preconceitos não são erros a eliminar, mas condição de possibilidade da compreensão.","resposta":""},
  {"id":"3789","tipo":"multipla","disciplina":"Sociologia","tema":"Saúde","subtema":"SUS","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O SUS (Sistema Único de Saúde) foi criado pela Constituição Federal de 1988. Qual é seu princípio fundamental?","alternativa_a":"Saúde como direito universal, integral e gratuito, financiado pelo Estado","alternativa_b":"Saúde apenas para trabalhadores contribuintes","alternativa_c":"Saúde como mercadoria vendida por planos privados","alternativa_d":"Saúde restrita a doenças infecciosas","alternativa_e":"Saúde gerida exclusivamente pelos municípios","resposta_correta":"a","explicacao":"O SUS (CF/1988, Art. 196) estabelece que 'saúde é direito de todos e dever do Estado'. Princípios: universalidade (todos têm direito), integralidade (atenção completa, da prevenção ao tratamento), equidade (priorizar os mais vulneráveis) e descentralização com controle social.","resposta":""},
  {"id":"3790","tipo":"multipla","disciplina":"Matemática","tema":"Matemática Financeira","subtema":"Juros Simples","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Um capital de R$ 1.000 é aplicado a juros simples de 2% ao mês por 6 meses. Qual é o montante final?","alternativa_a":"R$ 1.120","alternativa_b":"R$ 1.200","alternativa_c":"R$ 1.020","alternativa_d":"R$ 1.126,16","alternativa_e":"R$ 1.060","resposta_correta":"a","explicacao":"Juros simples: J = C × i × t = 1000 × 0,02 × 6 = R$ 120. Montante M = C + J = 1000 + 120 = R$ 1.120.","resposta":""},
  {"id":"3791","tipo":"multipla","disciplina":"Física","tema":"Mecânica dos Fluidos","subtema":"Empuxo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Princípio de Arquimedes afirma que todo corpo submerso em um fluido sofre um empuxo igual a:","alternativa_a":"O peso do fluido deslocado pelo corpo","alternativa_b":"O peso do próprio corpo","alternativa_c":"A pressão multiplicada pela área","alternativa_d":"A densidade do fluido vezes o volume do corpo","alternativa_e":"A massa do corpo vezes a gravidade","resposta_correta":"a","explicacao":"E = ρ_fluido × g × V_submerso = peso do fluido deslocado. Se E > peso do corpo, ele flutua; se E < peso, afunda; se E = peso, fica em equilíbrio submerso.","resposta":""},
  {"id":"3792","tipo":"multipla","disciplina":"Química","tema":"Polímeros","subtema":"PET","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O PET (politereftalato de etileno) é utilizado em garrafas plásticas. É um polímero obtido por:","alternativa_a":"Polimerização por condensação (poliéster)","alternativa_b":"Polimerização por adição","alternativa_c":"Fermentação","alternativa_d":"Oxidação catalítica","alternativa_e":"Hidrólise básica","resposta_correta":"a","explicacao":"PET é um poliéster formado pela condensação entre ácido tereftálico e etileno glicol, com liberação de água. É reciclável (código 1 — PET) e amplamente usado em embalagens, fibras sintéticas (poliéster) e filmes.","resposta":""},
  {"id":"3793","tipo":"multipla","disciplina":"Biologia","tema":"Botânica","subtema":"Briófitas","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Os musgos pertencem ao grupo das briófitas. Qual característica os diferencia das plantas vasculares?","alternativa_a":"Ausência de tecidos vasculares (xilema e floema) e dependência de água para a reprodução","alternativa_b":"Presença de frutos","alternativa_c":"Sementes nuas","alternativa_d":"Raízes verdadeiras","alternativa_e":"Folhas com nervuras vascularizadas","resposta_correta":"a","explicacao":"Briófitas (musgos, hepáticas, antóceros) são avasculares — sem xilema e floema. Absorvem água por toda a superfície. Para reprodução, os anterozoides (gametas masculinos) precisam nadar em água para alcançar o arquegônio. Por isso são restritas a ambientes úmidos.","resposta":""},
  {"id":"3794","tipo":"multipla","disciplina":"História","tema":"Brasil Contemporâneo","subtema":"Lula I e II","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Os governos Lula I e II (2003-2010) ficaram marcados por programas de redução da pobreza. Além do Bolsa Família, qual outra política de inclusão social foi implementada?","alternativa_a":"Expansão do ensino superior (REUNI, PROUNI e cotas raciais)","alternativa_b":"Privatização do SUS","alternativa_c":"Redução do salário mínimo","alternativa_d":"Extinção do FGTS","alternativa_e":"Criação do Banco Nacional","resposta_correta":"a","explicacao":"O governo Lula expandiu o ensino superior: REUNI (expansão das universidades federais), PROUNI (bolsas em faculdades privadas para estudantes de baixa renda), FIES (financiamento estudantil) e cotas raciais e sociais nas universidades federais. Essas políticas promoveram inédita inclusão de negros e pobres no ensino superior.","resposta":""},
  {"id":"3795","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Flexão Nominal","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O plural de 'cidadão' é:","alternativa_a":"cidadãos","alternativa_b":"cidadães","alternativa_c":"cidadões","alternativa_d":"cidadons","alternativa_e":"cidadãis","resposta_correta":"a","explicacao":"Palavras terminadas em '-ão' fazem plural em '-ãos' (cidadão/cidadãos, mão/mãos), '-ães' (pão/pães, cão/cães) ou '-ões' (limão/limões, balão/balões). Não há regra geral — deve-se memorizar. 'Cidadão' → 'cidadãos'.","resposta":""},
  {"id":"3796","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da História","subtema":"Hegel","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Para Hegel, o processo dialético da história move-se por:","alternativa_a":"Tese, antítese e síntese — contradições que se superam progressivamente","alternativa_b":"Ciclos eternos sem progresso","alternativa_c":"Vontade arbitrária dos governantes","alternativa_d":"Determinismo econômico","alternativa_e":"Forças naturais impessoais","resposta_correta":"a","explicacao":"A dialética hegeliana: toda realidade (e a história) move-se por contradições. Uma tese (afirmação) gera sua negação (antítese); o conflito se resolve em síntese, que se torna nova tese em nível superior. O Espírito (Geist) realiza-se progressivamente na história, atingindo a autoconsciência plena na liberdade.","resposta":""},
  {"id":"3797","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Sistemas Lineares Impossíveis","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O sistema {x + y = 5; x + y = 8} é classificado como:","alternativa_a":"Impossível — não tem solução (retas paralelas)","alternativa_b":"Possível determinado","alternativa_c":"Possível indeterminado","alternativa_d":"Dependente","alternativa_e":"Consistente","resposta_correta":"a","explicacao":"As equações têm os mesmos coeficientes das variáveis (x+y) mas diferentes termos independentes (5 ≠ 8). Geometricamente: retas paralelas que nunca se intersectam → sistema impossível (SI), sem solução.","resposta":""},
  {"id":"3798","tipo":"multipla","disciplina":"Química","tema":"Bioquímica","subtema":"Vitaminas","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A vitamina C (ácido ascórbico) é importante para:","alternativa_a":"Síntese de colágeno e função antioxidante","alternativa_b":"Coagulação do sangue","alternativa_c":"Visão noturna","alternativa_d":"Metabolismo do cálcio","alternativa_e":"Síntese de hormônios sexuais","resposta_correta":"a","explicacao":"Vitamina C: participa da síntese de colágeno (essencial para pele, ossos, vasos), é antioxidante (combate radicais livres) e favorece a absorção de ferro. Sua deficiência causa escorbuto (hemorragias, queda dos dentes). Presente em frutas cítricas.","resposta":""},
  {"id":"3799","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Espécies Invasoras","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"As espécies exóticas invasoras representam ameaça à biodiversidade porque:","alternativa_a":"Competem com espécies nativas, alteram habitats e podem levar espécies nativas à extinção","alternativa_b":"Sempre beneficiam os ecossistemas por aumentar a diversidade","alternativa_c":"São idênticas às espécies nativas em comportamento","alternativa_d":"Só afetam plantas, não animais","alternativa_e":"São extintas rapidamente no novo ambiente","resposta_correta":"a","explicacao":"Espécies invasoras (ex.: javali europeu no Brasil, mexilhão-dourado, capim-gordura) competem por recursos com nativas, predam espécies locais, alteram habitats (como o capim que aumenta a frequência de incêndios) e introduzem patógenos. São a 2ª maior causa de extinção de espécies no mundo.","resposta":""},
  {"id":"3800","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"América Latina","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A expressão 'quintal dos EUA' refere-se à:","alternativa_a":"Doutrina Monroe e à histórica influência e intervenção norte-americana na América Latina","alternativa_b":"Parceria econômica entre Brasil e EUA","alternativa_c":"Importação de tecnologia americana pela América Latina","alternativa_d":"Zona de livre comércio no Caribe","alternativa_e":"Aliança militar defensiva das Américas","resposta_correta":"a","explicacao":"A Doutrina Monroe (1823) — 'América para os americanos' — estabeleceu a América Latina como zona de influência dos EUA, justificando intervenções militares e políticas ao longo do séc. XX (Guatemala 1954, Cuba 1961, Chile 1973, Nicarágua 1980s). A expressão 'quintal dos EUA' critica essa dominação geopolítica.","resposta":""},
  {"id":"4521","tipo":"dissertativa","disciplina":"Matemática","tema":"Matemática Financeira","subtema":"Juros Compostos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Um capital de R$ 2.000 é aplicado a juros compostos de 3% ao mês por 3 meses. Calcule o montante final.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Juros compostos: M = C × (1 + i)^t = 2000 × (1,03)³. (1,03)³ = 1,03 × 1,03 × 1,03 = 1,0609 × 1,03 ≈ 1,0927. M = 2000 × 1,0927 ≈ R$ 2.185,45. Juros compostos geram mais que os simples (que dariam 2000 + 2000×0,03×3 = R$ 2.180).","resposta":"M ≈ R$ 2.185,45"},
  {"id":"4522","tipo":"dissertativa","disciplina":"Física","tema":"Termodinâmica","subtema":"Processos Termodinâmicos","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Diferencie os processos isotérmico, isobárico, isocórico e adiabático, citando a variável constante em cada um.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Processos termodinâmicos: (1) Isotérmico: temperatura constante (T = cte). PV = cte (lei de Boyle). (2) Isobárico: pressão constante (P = cte). V/T = cte (lei de Gay-Lussac/Charles). (3) Isocórico (isovolumétrivo): volume constante (V = cte). P/T = cte (lei de Gay-Lussac). (4) Adiabático: sem troca de calor com o exterior (Q = 0). A variação de energia interna é igual ao trabalho realizado: ΔU = −W.","resposta":"Isotérmico: T = cte; Isobárico: P = cte; Isocórico: V = cte; Adiabático: Q = 0"},
  {"id":"4523","tipo":"dissertativa","disciplina":"Química","tema":"Polímeros","subtema":"Borracha Sintética","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Por que o Brasil foi pioneiro na produção de borracha natural e quais os fatores que levaram à crise do ciclo da borracha amazônica?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O Brasil dominava a produção mundial de borracha natural (látex da Hevea brasiliensis, exclusiva da Amazônia) no final do séc. XIX, abastecendo a revolução industrial. Manaus e Belém enriqueceram (Teatro Amazonas, 1896). A crise veio quando o inglês Henry Wickham contrabandeou sementes da seringueira para a Kew Gardens (1876); as mudas foram cultivadas na Malásia e Ceilão (hoje Sri Lanka), onde eram mais produtivas e organizadas em plantações. Em 1912, a produção asiática superou a brasileira, derrubando os preços. O golpe final veio com a borracha sintética (petroquímica) desenvolvida durante a 2ª GM.","resposta":"Pioneirismo: borracha amazônica abastecia o mundo. Crise: contrabando das sementes por Wickham, plantações asiáticas mais produtivas e depois borracha sintética"},
  {"id":"4524","tipo":"dissertativa","disciplina":"Biologia","tema":"Saúde","subtema":"Vacinação","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Explique o mecanismo de ação das vacinas e o conceito de imunidade de rebanho.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"As vacinas funcionam introduzindo antígenos (patógenos mortos, atenuados, toxinas inativadas ou proteínas virais) que estimulam o sistema imune sem causar a doença. Os linfócitos B produzem anticorpos e células de memória. Numa infecção futura, o sistema imune reconhece o antígeno rapidamente e responde antes que a doença se instale. Imunidade de rebanho (coletiva): quando uma porcentagem suficiente da população está imunizada (vacinada ou recuperada), o patógeno não encontra hospedeiros suficientes para circular — protegendo também os não imunizados (imunossuprimidos, bebês, alérgicos a vacinas). O limiar varia por doença: sarampo exige ~95%; COVID-19 ~70-90%.","resposta":"Vacinas estimulam imunidade com memória sem causar doença. Imunidade de rebanho: população imunizada suficiente interrompe a cadeia de transmissão"},
  {"id":"4525","tipo":"dissertativa","disciplina":"História","tema":"Colonização","subtema":"Tratado de Tordesilhas","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique o Tratado de Tordesilhas (1494) e suas consequências para a formação territorial do Brasil.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O Tratado de Tordesilhas (1494) dividiu o mundo entre Portugal e Espanha por uma linha imaginária a 370 léguas a oeste das ilhas de Cabo Verde. Terras a leste → Portugal; a oeste → Espanha. Consequências para o Brasil: a maior parte do Brasil ficou a leste da linha (território português). O marco legal justificou a colonização portuguesa a partir de 1500. Porém, o Brasil real expandiu muito além da linha de Tordesilhas devido às bandeiras, missões jesuítas e guerras — o Tratado de Madri (1750) e o Uti Possidetis consolidaram o território ampliado.","resposta":"Tordesilhas (1494): linha divisória leste-oeste atribuiu Brasil a Portugal. O território real expandiu com bandeiras e foi consolidado pelo Tratado de Madri (1750)"},
  {"id":"4526","tipo":"dissertativa","disciplina":"Língua Portuguesa","tema":"Redação","subtema":"Proposta de Intervenção","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"No ENEM, a proposta de intervenção da redação deve conter cinco elementos. Quais são eles?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"A proposta de intervenção do ENEM deve ter: (1) Ação: o que fazer (verbo de ação + medida concreta); (2) Agente: quem vai executar (governo federal, municipal, ONGs, escola, mídia etc.); (3) Modo/meio: como será feito (por meio de campanhas, leis, políticas públicas, etc.); (4) Efeito/finalidade: para quê, qual o objetivo esperado; (5) Detalhamento: complemento que especifica a ação. Mnemônico: AAMED (Ação, Agente, Meio, Efeito, Detalhamento). A proposta deve ser relacionada ao tema e respeitar os direitos humanos.","resposta":"Ação, Agente, Modo/meio, Efeito e Detalhamento — os 5 elementos da proposta de intervenção do ENEM"},
  {"id":"4527","tipo":"dissertativa","disciplina":"Filosofia","tema":"Lógica","subtema":"Falácias","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que são falácias lógicas? Explique dois tipos com exemplos.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Falácias são argumentos que parecem válidos mas têm falhas lógicas. (1) Ad hominem: atacar o caráter do interlocutor em vez de refutar o argumento. Ex.: 'Não ouça sua proposta — ele é desonesto.' Erro: caráter pessoal não invalida um argumento; (2) Falsa dicotomia: apresentar apenas duas opções quando existem outras. Ex.: 'Ou você apoia esta guerra, ou é traidor da nação.' Outros exemplos: Apelo à autoridade indevida, Causa falsa (post hoc ergo propter hoc), Slippery slope, Generalização apressada.","resposta":"Falácias: argumentos com falhas lógicas. Ad hominem: atacar a pessoa; Falsa dicotomia: apresentar apenas duas opções quando há mais"},
  {"id":"4528","tipo":"dissertativa","disciplina":"Sociologia","tema":"Direitos","subtema":"Estatuto da Criança e do Adolescente","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"O que é o ECA (Estatuto da Criança e do Adolescente) e quais são seus princípios fundamentais?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O ECA (Lei 8.069/1990) é o marco legal que regula os direitos de crianças (até 12 anos) e adolescentes (12 a 18 anos) no Brasil. Princípios fundamentais: (1) Proteção integral: crianças e adolescentes têm todos os direitos humanos em pleno; (2) Prioridade absoluta: suas necessidades têm precedência nas políticas públicas; (3) Condição de sujeitos de direito: não são objetos de tutela, mas sujeitos com direitos; (4) Melhor interesse da criança: decisões devem considerar prioritariamente o bem da criança. Proíbe trabalho infantil, tráfico, exploração sexual e violência.","resposta":"ECA (1990): proteção integral, prioridade absoluta e condição de sujeito de direito para crianças e adolescentes no Brasil"},
  {"id":"4529","tipo":"dissertativa","disciplina":"Geografia","tema":"Geopolítica","subtema":"África do Sul","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Após o fim do apartheid, quais desafios socioeconômicos a África do Sul ainda enfrenta?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Apesar do fim formal do apartheid em 1994 e da eleição de Mandela, a África do Sul enfrenta: (1) Desigualdade racial persistente: o Gini é um dos mais altos do mundo (0,63); brancos ainda concentram riqueza e propriedades; (2) Desemprego elevado: acima de 30%, especialmente entre jovens negros; (3) Violência e criminalidade: uma das maiores taxas de homicídios do mundo; (4) Crise energética: apagões frequentes (load shedding) pela falência da Eskom (empresa elétrica estatal); (5) Corrupção: o governo Zuma (2009-18) foi marcado por escândalos de corrupção (state capture).","resposta":"Desigualdade racial extrema, desemprego crônico, violência, crise energética e corrupção — legados do apartheid que persistem na África do Sul contemporânea"},
  {"id":"4530","tipo":"dissertativa","disciplina":"Matemática","tema":"Geometria Analítica","subtema":"Cônicas","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"O que são cônicas? Classifique as cônicas com base nos coeficientes de x² e y² em suas equações.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Cônicas são curvas formadas pela interseção de um plano com um cone duplo. Classificação pela equação Ax² + Cy² + Dx + Ey + F = 0: (1) Circunferência: A = C (coeficientes iguais) e A, C > 0. Ex.: x² + y² = 25. (2) Elipse: A ≠ C mas ambos do mesmo sinal. Ex.: x²/9 + y²/4 = 1. (3) Hipérbole: A e C de sinais opostos. Ex.: x²/9 − y²/4 = 1. (4) Parábola: apenas um dos termos quadráticos (A = 0 ou C = 0). Ex.: y = x². Aplicações: órbitas planetárias (elipses), trajetórias balísticas (parábolas), telescópios (paraboloides).","resposta":"Circunferência (A=C), elipse (A≠C, mesmo sinal), hipérbole (sinais opostos), parábola (só um quadrático) — cônicas como seções do cone"},
]

